#include <bits/stdc++.h>
using namespace std;

int main()
{
    int x, y;
    int result;
    cin >> x >> y;

    int carry = 0, count = 0, sum = 0;

    while (x != 0 || y != 0) {
        int val1 = x % 10;
        int val2 = y % 10;

        sum = carry + val1 + val2;

        if (sum > 9) {
            carry = 1;
            count++;
        } else {
            carry = 0;
        }

        x = x / 10;
        y = y / 10;
    }
    cout << count << "\n";

    return 0;
}

